<template>
	<view class="container">
		<div class="box2">
			<!-- 标题 -->
			<Mtitle title="Supply"></Mtitle>

			<!-- 订单列表 -->
			<view class="box">
				<view class="scrollContent">
					<scroll-view scroll-y="true" class="scrollView">
						<!-- 加载中 -->
						<view v-if="loading" class="loading" style="text-align: center; padding: 20px;">
							<text>加载中...</text>
						</view>

						<!-- 没有数据 -->
						<view v-else-if="orders.length === 0" class="empty"
							style="text-align: center; color: #999; padding: 20px;">
							<text>暂无订单</text>
						</view>

						<!-- 动态渲染订单 -->
						<order v-for="order in orders" :key="order.order_id" :title="order.title"
							:customer="order.customer_username || '未知客户'" :content="order.description || '暂无描述'"
							class="as" />
					</scroll-view>
				</view>
			</view>

			<!-- 导航按钮 -->
			<navigator url="/pages/orderDetails/orderDetails"></navigator>

			<!-- 底部按钮组 -->
			<view class="buttonLump">
				<newBar title="new" to="/pages/orders/orders"></newBar>
				<newBar title="post" to="/pages/orderDetails/orderDetails"></newBar>
			</view>
		</div>
	</view>
</template>

<script setup>
	import {
		onMounted,
		ref
	} from 'vue'

	// 1. 定义响应式数据
	const orders = ref([]) // 订单列表
	const loading = ref(true) // 加载状态

	// 2. 获取我的订单数据
	const getMyOrders = async () => {
		loading.value = true

		try {
			// 获取 token
			const token = uni.getStorageSync('token')
			if (!token) {
				uni.showToast({
					title: '请先登录',
					icon: 'none'
				})
				return
			}

			const res = await uni.request({
				url: 'http://localhost:5000/api/orders/supply',
				method: 'GET',
				header: {
					'Authorization': `Bearer ${token}`,
					'Content-Type': 'application/json'
				}
			})

			// 处理响应
			if (res.statusCode === 200 && res.data.success) {
				orders.value = res.data.data // 赋值订单列表
				console.log('获取到的订单数据:', res.data.data)
			} else {
				uni.showToast({
					title: res.data.message || '获取失败',
					icon: 'none'
				})
			}
		} catch (error) {
			console.error('获取订单失败:', error)
			uni.showToast({
				title: '网络错误',
				icon: 'none'
			})
		} finally {
			loading.value = false
		}
	}

	// 3. 页面加载时获取数据
	onMounted(() => {
		getMyOrders()
	})
</script>

<style scoped>
	.buttonLump {
		margin-top: 50px;
	}

	.scrollView {
		height: 830rpx;
	}

	.scrollContent {
		display: flex;
		justify-content: center;
		margin-top: 20rpx;
	}

	.container {
		background-image: url('@/static/images/background/屏幕截图 2025-08-11 135908.png');
		background-size: cover;
		background-position: center center;
		background-repeat: no-repeat;
		background-attachment: fixed;
		width: 100%;
		height: 100vh;
	}

	.as {
		margin-top: 5px;
	}
</style>